#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
int n;
char c[25];
void DFS(int num,int sum,int x)
{
    if(num==n)
    {
        if(!(sum+x))
        {
            printf("%s\n",c);
        }
        return;
    }
    c[num*2-1]=' ';//' '
    if(x>0)
    {
        DFS(num+1,sum,x*10+num+1);
    }
    else
    {
        DFS(num+1,sum,x*10-num-1);
    }
    c[num*2-1]='+';//+
    DFS(num+1,sum+x,num+1);
    c[num*2-1]='-';//-
    DFS(num+1,sum+x,-(num+1));
}

int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d",&n);
    for(int i=0;i<n;i++)
    {
        c[i*2]=i+'1';
    }
    DFS(1,0,1);
	return false;
}
